t.script:
                //
(function(){
'use strict';

var PRIORITY_LABELS = {any:'Any',low:'Low',medium:'Medium',high:'High',urgent:'Urgent'};
var PRIORITY_COLORS = {any:'secondary',low:'info',medium:'primary',high:'warning',urgent:'danger'};

function slaAlert(msg, type){
    var el = document.getElementById('slaAlert');
    if(!el) return;
    el.className = 'alert alert-' + (type||'success') + ' mb-3';
    el.textContent = msg;
    setTimeout(function(){ el.className = 'd-none'; }, 4000);
}

function slaLoadPolicies(){
    fetch('/customer_support/sla/policies', {credentials:'same-origin'})
    .then(function(r){ return r.json(); })
    .then(function(d){
        var tbody = document.getElementById('slaPoliciesBody');
        if(!tbody) return;
        if(!d.policies || d.policies.length === 0){
            tbody.innerHTML = '<tr><td colspan="5" class="text-center text-muted py-3"><i class="bi bi-inbox me-2"></i>No SLA policies defined yet. Add one above.</td></tr>';
            return;
        }
        tbody.innerHTML = d.policies.map(function(p){
            var pc = PRIORITY_COLORS[p.priority_level] || 'secondary';
            var pl = PRIORITY_LABELS[p.priority_level] || p.priority_level;
            return '<tr>' +
                '<td><strong>' + p.name + '</strong></td>' +
                '<td><span class="badge bg-dark">' + p.response_time + ' ' + p.time_unit + '</span></td>' +
                '<td><span class="badge bg-' + pc + '">' + pl + '</span></td>' +
                '<td><small class="text-muted">' + (p.description || '-') + '</small></td>' +
                '<td>' +
                    '<button class="btn btn-sm btn-outline-primary me-1" onclick="slaOpenEdit(' + JSON.stringify(p) + ')" title="Edit"><i class="bi bi-pencil"></i></button>' +
                    '<button class="btn btn-sm btn-outline-danger" onclick="slaDelete(' + p.id + ',\'' + p.name + '\')" title="Delete"><i class="bi bi-trash3"></i></button>' +
                '</td>' +
            '</tr>';
        }).join('');
    })
    .catch(function(e){ console.warn('SLA load failed:', e); });
}

window.slaCreate = function(e){
    e.preventDefault();
    var form = document.getElementById('slaCreateForm');
    var data = new FormData(form);
    var csrf = document.querySelector('input[name="csrf_token"]');
    if(csrf) data.set('csrf_token', csrf.value);
    fetch('/customer_support/sla/create', {method:'POST', credentials:'same-origin', body: new URLSearchParams(data)})
    .then(function(r){
        if(r.redirected || r.ok){
            slaAlert('SLA policy created successfully!', 'success');
            form.reset();
            slaLoadPolicies();
        } else {
            slaAlert('Failed to create policy.', 'danger');
        }
    })
    .catch(function(){ slaAlert('Network error.', 'danger'); });
};

window.slaOpenEdit = function(p){
    document.getElementById('editSlaId').value = p.id;
    document.getElementById('editSlaName').value = p.name;
    document.getElementById('editSlaTime').value = p.response_time;
    document.getElementById('editSlaUnit').value = p.time_unit;
    document.getElementById('editSlaPriority').value = p.priority_level;
    document.getElementById('editSlaDesc').value = p.description || '';
    var modal = new bootstrap.Modal(document.getElementById('slaEditModal'));
    modal.show();
};

window.slaSaveEdit = function(){
    var id = document.getElementById('editSlaId').value;
    var data = new URLSearchParams({
        sla_name: document.getElementById('editSlaName').value,
        sla_response_time: document.getElementById('editSlaTime').value,
        sla_time_unit: document.getElementById('editSlaUnit').value,
        sla_priority_level: document.getElementById('editSlaPriority').value,
        sla_description: document.getElementById('editSlaDesc').value,
    });
    var csrf = document.querySelector('input[name="csrf_token"]');
    if(csrf) data.set('csrf_token', csrf.value);
    fetch('/customer_support/sla/' + id + '/update', {method:'POST', credentials:'same-origin', body: data})
    .then(function(r){ return r.json(); })
    .then(function(d){
        bootstrap.Modal.getInstance(document.getElementById('slaEditModal')).hide();
        if(d.success){
            slaAlert('SLA policy updated.', 'success');
            slaLoadPolicies();
        } else {
            slaAlert('Update failed: ' + (d.error||'unknown'), 'danger');
        }
    });
};

window.slaDelete = function(id, name){
    if(!confirm('Delete SLA policy "' + name + '"? This cannot be undone.')) return;
    fetch('/customer_support/sla/' + id + '/delete', {method:'POST', credentials:'same-origin'})
    .then(function(r){ return r.json(); })
    .then(function(d){
        if(d.success){ slaAlert('Policy deleted.', 'success'); slaLoadPolicies(); }
        else { slaAlert('Delete failed.', 'danger'); }
    });
};

// Load policies when ticket settings modal opens
document.addEventListener('DOMContentLoaded', function(){
    var modal = document.getElementById('ticketSettingsModal');
    if(modal){
        modal.addEventListener('shown.bs.modal', function(){ slaLoadPolicies(); });
    }
});

})();
