(function() {
    'use strict';
    function activateTabFromURL() {
        var urlParams = new URLSearchParams(window.location.search);
        var tabParam = urlParams.get('tab');
        var hashParam = window.location.hash.substring(1);
        var targetTab = tabParam || hashParam;
        if (targetTab) {
            var targetSelector = '#' + targetTab;
            var tabButton = document.querySelector('.header-left button[data-bs-target="' + targetSelector + '"]');
            if (tabButton) {
                document.querySelectorAll('.header-left button').forEach(function(btn) {
                    btn.classList.remove('active');
                    btn.setAttribute('aria-selected', 'false');
                });
                document.querySelectorAll('.tab-pane').forEach(function(pane) {
                    pane.classList.remove('show', 'active');
                });
                tabButton.classList.add('active');
                tabButton.setAttribute('aria-selected', 'true');
                var targetPane = document.querySelector(targetSelector);
                if (targetPane) { targetPane.classList.add('show', 'active'); }
            }
        }
    }
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', activateTabFromURL);
    } else { activateTabFromURL(); }
    window.addEventListener('load', activateTabFromURL);
    window.addEventListener('hashchange', activateTabFromURL);
    document.addEventListener('DOMContentLoaded', function() {
        var triggerTabList = [].slice.call(document.querySelectorAll('.header-left button[data-bs-toggle="tab"]'));
        triggerTabList.forEach(function(triggerEl) {
            triggerEl.addEventListener('click', function(event) {
                event.preventDefault();
                new bootstrap.Tab(triggerEl).show();
            });
        });
        triggerTabList.forEach(function(tab) {
            tab.addEventListener('shown.bs.tab', function(e) {
                localStorage.setItem('activeDashboardTab', e.target.getAttribute('data-bs-target'));
            });
        });
        document.querySelectorAll('.action-card[data-bs-toggle="tab"]').forEach(function(card) {
            card.addEventListener('click', function(e) {
                e.preventDefault();
                var tab = document.querySelector('.header-left button[data-bs-target="' + this.getAttribute('href') + '"]');
                if (tab) new bootstrap.Tab(tab).show();
            });
        });
        activateTabFromURL();
        document.querySelectorAll('.alert-success, .alert-danger').forEach(function(alert) {
            setTimeout(function() { new bootstrap.Alert(alert).close(); }, 5000);
        });
    });
})();
