(function(){
'use strict';

var currentDays = 30;
var charts = {};

var STATUS_COLORS = {
    new:         '#3498db',
    assigned:    '#9b59b6',
    in_progress: '#e8b84b',
    resolved:    '#2ecc71',
    closed:      '#95a5a6',
};
var PRIORITY_COLORS = {
    urgent: '#e74c3c',
    high:   '#e67e22',
    medium: '#3498db',
    low:    '#2ecc71',
};

function destroyChart(id){
    if(charts[id]){ charts[id].destroy(); delete charts[id]; }
}

function buildVolumeChart(trend){
    destroyChart('volume');
    var ctx = document.getElementById('volumeChart');
    if(!ctx) return;
    charts['volume'] = new Chart(ctx, {
        type: 'bar',
        data: {
            labels: trend.map(function(d){ return d.date; }),
            datasets: [{
                label: 'Tickets',
                data: trend.map(function(d){ return d.count; }),
                backgroundColor: 'rgba(26,58,92,0.75)',
                borderColor: '#1a3a5c',
                borderWidth: 1,
                borderRadius: 4,
            }]
        },
        options: {
            responsive: true,
            plugins: { legend: { display: false } },
            scales: {
                y: { beginAtZero: true, ticks: { stepSize: 1 } },
                x: { ticks: { maxTicksLimit: 14, maxRotation: 45 } }
            }
        }
    });
}

function buildStatusChart(breakdown){
    destroyChart('status');
    var ctx = document.getElementById('statusChart');
    if(!ctx) return;
    var labels = Object.keys(breakdown);
    charts['status'] = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: labels.map(function(l){ return l.replace('_',' ').replace(/\b\w/g,function(c){return c.toUpperCase();}); }),
            datasets: [{
                data: Object.values(breakdown),
                backgroundColor: labels.map(function(l){ return STATUS_COLORS[l] || '#aaa'; }),
                borderWidth: 2,
                borderColor: '#fff',
            }]
        },
        options: {
            responsive: true,
            plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } } },
            cutout: '60%',
        }
    });
}

function buildPriorityChart(dist){
    destroyChart('priority');
    var ctx = document.getElementById('priorityChart');
    if(!ctx) return;
    var labels = ['urgent','high','medium','low'];
    charts['priority'] = new Chart(ctx, {
        type: 'pie',
        data: {
            labels: ['Urgent','High','Medium','Low'],
            datasets: [{
                data: labels.map(function(l){ return dist[l] || 0; }),
                backgroundColor: labels.map(function(l){ return PRIORITY_COLORS[l]; }),
                borderWidth: 2,
                borderColor: '#fff',
            }]
        },
        options: {
            responsive: true,
            plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } } },
        }
    });
}

function buildCustomersChart(customers){
    destroyChart('customers');
    var ctx = document.getElementById('customersChart');
    if(!ctx) return;
    charts['customers'] = new Chart(ctx, {
        type: 'bar',
        data: {
            labels: customers.map(function(c){ return c.name; }),
            datasets: [{
                label: 'Tickets',
                data: customers.map(function(c){ return c.count; }),
                backgroundColor: 'rgba(232,184,75,0.85)',
                borderColor: '#e8b84b',
                borderWidth: 1,
                borderRadius: 4,
            }]
        },
        options: {
            indexAxis: 'y',
            responsive: true,
            plugins: { legend: { display: false } },
            scales: { x: { beginAtZero: true, ticks: { stepSize: 1 } } }
        }
    });
}

function healthBadge(h){
    var map = {
        green: '<span class="badge bg-success">Good</span>',
        amber: '<span class="badge bg-warning text-dark">Attention</span>',
        red:   '<span class="badge bg-danger">Critical</span>'
    };
    return map[h] || '<span class="badge bg-secondary">-</span>';
}

function trendIcon(t){
    if(t === 'up')   return '<span class="text-danger"><i class="bi bi-arrow-up-right-circle-fill"></i> Up</span>';
    if(t === 'down') return '<span class="text-success"><i class="bi bi-arrow-down-right-circle-fill"></i> Down</span>';
    return '<span class="text-muted"><i class="bi bi-dash-circle"></i> Stable</span>';
}

function scoreBar(val, color){
    return '<div style="display:flex;align-items:center;gap:6px;">' +
        '<div style="flex:1;background:#e9ecef;border-radius:4px;height:8px;overflow:hidden;">' +
        '<div style="width:' + val + '%;height:100%;background:' + color + ';border-radius:4px;"></div></div>' +
        '<span style="font-size:11px;font-weight:600;width:36px;">' + val + '%</span></div>';
}

function rateColor(v){ return v >= 80 ? '#2ecc71' : v >= 60 ? '#f39c12' : '#e74c3c'; }

function buildProjectTable(rows, days){
    var tbody = document.getElementById('projectHealthBody');
    if(!tbody) return;
    if(!rows || rows.length === 0){
        tbody.innerHTML = '<tr><td colspan="8" class="text-center text-muted py-4">No projects found.</td></tr>';
        return;
    }
    tbody.innerHTML = rows.map(function(p){
        return '<tr>' +
            '<td class="ps-3"><strong>' + p.name + '</strong>' +
                (p.code ? ' <span class="badge bg-secondary ms-1" style="font-size:10px;">' + p.code + '</span>' : '') +
            '</td>' +
            '<td>' + p.total + '</td>' +
            '<td>' + p.resolved + '</td>' +
            '<td>' + p.open + '</td>' +
            '<td>' + (p.breached > 0 ? '<span class="text-danger fw-bold">' + p.breached + '</span>' : p.breached) + '</td>' +
            '<td>' + healthBadge(p.health) + '</td>' +
            '<td>' + trendIcon(p.trend) + '</td>' +
            '<td class="pe-3"><a href="/customer_support/admin/report/project/' + p.id + '?days=' + days + '" target="_blank" class="btn btn-sm btn-outline-primary" style="font-size:11px;"><i class="bi bi-printer me-1"></i>Print</a></td>' +
        '</tr>';
    }).join('');
}

function buildFocalTable(rows, days){
    var tbody = document.getElementById('focalLeaderboardBody');
    if(!tbody) return;
    if(!rows || rows.length === 0){
        tbody.innerHTML = '<tr><td colspan="9" class="text-center text-muted py-4">No focal persons found.</td></tr>';
        return;
    }
    var medals = ['🥇','🥈','🥉'];
    tbody.innerHTML = rows.map(function(fp, i){
        return '<tr>' +
            '<td class="ps-3">' + (medals[i] || (i+1)) + '</td>' +
            '<td><strong>' + fp.name + '</strong></td>' +
            '<td>' + fp.assigned + '</td>' +
            '<td>' + fp.resolved + '</td>' +
            '<td>' + fp.open + '</td>' +
            '<td>' + (fp.breached > 0 ? '<span class="text-danger fw-bold">' + fp.breached + '</span>' : fp.breached) + '</td>' +
            '<td>' + scoreBar(fp.resolve_rate, rateColor(fp.resolve_rate)) + '</td>' +
            '<td>' + scoreBar(fp.sla_rate, rateColor(fp.sla_rate)) + '</td>' +
            '<td class="pe-3"><a href="/customer_support/admin/report/focal/' + fp.id + '?days=' + days + '" target="_blank" class="btn btn-sm btn-outline-primary" style="font-size:11px;"><i class="bi bi-printer me-1"></i>Print</a></td>' +
        '</tr>';
    }).join('');
}

function loadReportData(days){
    fetch('/customer_support/admin/reporting/data?days=' + days, {
        credentials: 'same-origin',
        headers: {'Accept': 'application/json'}
    })
    .then(function(r){ return r.json(); })
    .then(function(d){
        if(!d.success) return;
        var s = d.summary || {};

        document.getElementById('r-total-period').textContent  = s.total_period || 0;
        document.getElementById('r-resolved').textContent      = s.resolved_period || 0;
        document.getElementById('r-open').textContent          = s.open_tickets || 0;
        document.getElementById('r-breached').textContent      = s.breached_period || 0;
        document.getElementById('r-sla-compliance').textContent = (s.sla_compliance || 0) + '%';
        document.getElementById('r-resolve-rate').textContent  = (s.resolve_rate || 0) + '%';

        buildVolumeChart(d.volume_trend || []);
        buildStatusChart(d.status_breakdown || {});
        buildPriorityChart(d.priority_dist || {});
        buildCustomersChart(d.top_customers || []);

        buildProjectTable(d.project_health || [], days);
        buildFocalTable(d.focal_leaderboard || [], days);

        var el = document.getElementById('execReportLink');
        if(el) el.href = '/customer_support/admin/report/executive?days=' + days;
    })
    .catch(function(e){ console.warn('Report data load failed:', e); });
}

document.addEventListener('DOMContentLoaded', function(){
    // Day filter buttons
    var group = document.getElementById('reportDaysGroup');
    if(group){
        group.addEventListener('click', function(e){
            var btn = e.target.closest('button[data-days]');
            if(!btn) return;
            group.querySelectorAll('button').forEach(function(b){ b.classList.remove('active'); });
            btn.classList.add('active');
            currentDays = parseInt(btn.getAttribute('data-days'));
            loadReportData(currentDays);
        });
    }

    // Load when Reporting tab is clicked
    var reportTab = document.getElementById('reporting-tab');
    if(reportTab){
        reportTab.addEventListener('shown.bs.tab', function(){
            loadReportData(currentDays);
        });
        // Load immediately if already on reporting tab
        if(reportTab.classList.contains('active')){
            loadReportData(currentDays);
        }
    }

    // Load if URL param says tab=reporting
    var params = new URLSearchParams(window.location.search);
    if(params.get('tab') === 'reporting' || window.location.hash === '#reporting'){
        setTimeout(function(){ loadReportData(currentDays); }, 400);
    }
});

})();
